-- ============================================-- Добавление company_id в таблицу expenses-- ============================================ALTER TABLE expenses ADD COLUMN IF NOT EXISTS company_id UUID REFERENCES companies(id) ON DELETE CASCADE;-- Обновление RLS политик для учёта company_idDROP POLICY IF EXISTS "Users can view own expenses" ON expenses;DROP POLICY IF EXISTS "Users can insert own expenses" ON expenses;DROP POLICY IF EXISTS "Users can update own expenses" ON expenses;DROP POLICY IF EXISTS "Users can delete own expenses" ON expenses;CREATE POLICY "expenses_select_company" ON expenses  FOR SELECT USING (    EXISTS (      SELECT 1 FROM company_members cm      WHERE cm.company_id = expenses.company_id      AND cm.user_id = auth.uid()      AND cm.status = 'active'    )  );CREATE POLICY "expenses_insert_company" ON expenses  FOR INSERT WITH CHECK (    EXISTS (      SELECT 1 FROM company_members cm      WHERE cm.company_id = expenses.company_id      AND cm.user_id = auth.uid()      AND cm.status = 'active'    )  );CREATE POLICY "expenses_update_company" ON expenses  FOR UPDATE USING (    EXISTS (      SELECT 1 FROM company_members cm      WHERE cm.company_id = expenses.company_id      AND cm.user_id = auth.uid()      AND cm.status = 'active'    )  );CREATE POLICY "expenses_delete_company" ON expenses  FOR DELETE USING (    EXISTS (      SELECT 1 FROM company_members cm      WHERE cm.company_id = expenses.company_id      AND cm.user_id = auth.uid()      AND cm.status = 'active'    )  );